function j:Parent()return not b:IsStudio()and(gethui and gethui()or e:WaitForChild("PlayerGui"))or e:WaitForChild("PlayerGui")end
function j:Hex(h)h=h:gsub("#","")return Color3.fromRGB(tonumber(h:sub(1,2),16)or 0,tonumber(h:sub(3,4),16)or 0,tonumber(h:sub(5,6),16)or 0)end
function j:Create(C,P)f=Instance.new(C)for k,v in P do f[k]=v end return f end
function j:Draggable(fr)g,h,i,f=false,nil,nil,nil fr.InputBegan:Connect(function(inp)if inp.UserInputType==Enum.UserInputType.MouseButton1 or inp.UserInputType==Enum.UserInputType.Touch then g,i,f=true,inp.Position,fr.Position inp.Changed:Connect(function()if inp.UserInputState==Enum.UserInputState.End then g=false end end)end end)fr.InputChanged:Connect(function(inp)if inp.UserInputType==Enum.UserInputType.MouseMovement or inp.UserInputType==Enum.UserInputType.Touch then h=inp end end)c.InputChanged:Connect(function(inp)if inp==h and g then f=inp.Position-i d:Create(fr,TweenInfo.new(0.3),{Position=UDim2.new(f.X.Scale,f.X.Offset+f.X,f.Y.Scale,f.Y.Offset+f.Y)}):Play()end end)end
function j:Button(p)return j:Create("TextButton",{Name="Click",Parent=p,BackgroundColor3=Color3.fromRGB(255,255,255),BackgroundTransparency=1,BorderSizePixel=0,Size=UDim2.new(1,0,1,0),Font=Enum.Font.SourceSans,Text="",TextSize=14,ZIndex=p.ZIndex+3})end
function j:Tween(i)return d:Create(i.v,TweenInfo.new(i.t,Enum.EasingStyle[i.s],Enum.EasingDirection[i.d]),i.g)end
function j.Effect(c,p)p.ClipsDescendants=true f=e:GetMouse()g,h=f.X-c.AbsolutePosition.X,f.Y-c.AbsolutePosition.Y if g<0 or h<0 or g>c.AbsoluteSize.X or h>c.AbsoluteSize.Y then return end i=j:Create("Frame",{Parent=p,BackgroundColor3=Color3.fromRGB(255,255,255),BackgroundTransparency=0.75,BorderSizePixel=0,AnchorPoint=Vector2.new(0.5,0.5),Position=UDim2.new(0,g,0,h),Size=UDim2.new(0,0,0,0),ZIndex=p.ZIndex})j:Create("UICorner",{Parent=i,CornerRadius=UDim.new(1,0)})f=d:Create(i,TweenInfo.new(2.5,Enum.EasingStyle.Back,Enum.EasingDirection.Out),{Size=UDim2.new(0,c.AbsoluteSize.X*1.5,0,c.AbsoluteSize.X*1.5),BackgroundTransparency=1})f.Completed:Once(function()i:Destroy()end)f:Play()end
function j:Asset(r)if typeof(r)=='number'then return"rbxassetid://"..r end if typeof(r)=='string'then if not r:find('rbxassetid://')then if j.Lucide[r]then return j.Lucide[r]end if j.Lucide["lucide-"..r]then return j.Lucide["lucide-"..r]end end return r end return r end

-- Config System
j.ConfigFolder = "VitaUIConfigs"
function j:SaveConfig(n)if not isfolder(j.ConfigFolder)then makefolder(j.ConfigFolder)end f=j.ConfigFolder.."/"..n..".json"writefile(f,game:GetService("HttpService"):JSONEncode(j.ConfigData))return true end
function j:LoadConfig(n)f=j.ConfigFolder.."/"..n..".json"if not isfile(f)then return false end g=game:GetService("HttpService"):JSONDecode(readfile(f))for k,v in pairs(g)do j.ConfigData[k]=v if j.ConfigCallbacks[k]then pcall(j.ConfigCallbacks[k],v)end end return true end
function j:GetConfigs()if not isfolder(j.ConfigFolder)then makefolder(j.ConfigFolder)return{}end f={}for _,v in pairs(listfiles(j.ConfigFolder))do if v:find(".json")then g=v:gsub(j.ConfigFolder.."/",""):gsub(".json","")table.insert(f,g)end end return f end
function j:DeleteConfig(n)f=j.ConfigFolder.."/"..n..".json"if isfile(f)then delfile(f)return true end return false end
function j:RenameConfig(o,n)f,g=j.ConfigFolder.."/"..o..".json",j.ConfigFolder.."/"..n..".json"if isfile(f)then h=readfile(f)writefile(g,h)delfile(f)return true end return false end
function j:RegisterConfigValue(k,v,cb)j.ConfigData[k]=v j.ConfigCallbacks[k]=cb end

